import React, { useState } from 'react';
import {
  CContainer,
  CRow,
  CCol,
  CCard,
  CCardBody,
  CForm,
  CFormInput,
  CButton,
  CImage
} from '@coreui/react';

const Login = () => {
  const [formValues, setFormValues] = useState({ email: '', password: '' });
  const [errors, setErrors] = useState({});

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormValues({ ...formValues, [name]: value });
    setErrors({ ...errors, [name]: '' });
  };

  const validateForm = () => {
    const newErrors = {};
    if (!formValues.email) newErrors.email = 'Email is required';
    if (!formValues.password) newErrors.password = 'Password is required';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (validateForm()) {
      console.log('Form submitted:', formValues);
      // Handle login logic
    }
  };

  return (
    <div className="login-page-bg min-vh-100 d-flex align-items-center justify-content-center">
      <CContainer>
        <CRow className="justify-content-center">
          <CCol md={10} lg={8} xl={7}>
            <CCard className="login-card flex-md-row overflow-hidden">
              <CCol md={6} className="login-image-container p-0 d-none d-md-block">
                <CImage
                  src="https://mdbcdn.b-cdn.net/img/Photos/new-templates/bootstrap-login-form/img1.webp"
                  alt="login image"
                  className="w-100 h-100 login-image object-fit-cover"
                />
              </CCol>
              <CCol xs={12} md={6}>
                <CCardBody className="p-4">
                  <div className="text-center mb-4">
                    <img
                      src="/logo.png" // Replace with your logo path
                      alt="Logo"
                      className="login-logo mb-3"
                    />
                    <h5>Sign into your account</h5>
                  </div>
                  <CForm onSubmit={handleSubmit}>
                    <CFormInput
                      type="email"
                      name="email"
                      placeholder="Email address"
                      className="mb-3"
                      value={formValues.email}
                      onChange={handleChange}
                      invalid={!!errors.email}
                      feedbackInvalid={errors.email}
                    />
                    <CFormInput
                      type="password"
                      name="password"
                      placeholder="Password"
                      className="mb-3"
                      value={formValues.password}
                      onChange={handleChange}
                      invalid={!!errors.password}
                      feedbackInvalid={errors.password}
                    />
                    <div className="d-grid mb-3">
                      <CButton type="submit" className="login-btn">
                        LOGIN
                      </CButton>
                    </div>
                    <div className="text-center mb-2">
                      <a href="#" className="small text-muted">Forgot password?</a>
                    </div>
                    <div className="text-center">
                      <span>Don't have an account? </span>
                      <a href="#" className="fw-bold text-decoration-none">Register here</a>
                    </div>
                  </CForm>
                </CCardBody>
              </CCol>
            </CCard>
          </CCol>
        </CRow>
      </CContainer>
    </div>
  );
};

export default Login;
